  // Conservative workaround: skip SLP on riscv64 with vector extension to avoid non-dominating intrinsics.
  if (F.getParent() && F.getParent()->getTargetTriple().startswith("riscv64")) {
    if (F.hasFnAttribute("target-features") &&
        StringRef(F.getFnAttribute("target-features").getValueAsString()).contains("+v"))
      return PreservedAnalyses::all();
  }/' llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp && submit-patch
```

